export function getAvailableDestinations(selectedLocations: string[]): string[] {
  if (selectedLocations.length === 0) return DESTINATION_LIST;
  const geoTags = new Set<GeoTag>();
  for (const loc of selectedLocations) {
    const tags = LOCATION_TAGS[loc];
    if (!tags) return DESTINATION_LIST;
    tags.forEach((t) => geoTags.add(t));
  }
  return DESTINATION_LIST.filter((dest) => {
    const destTags = DESTINATION_GEO_TAGS[dest] ?? [];
    return destTags.some((t) => geoTags.has(t));
  });
}
